import React from "react";
import { Link } from "react-router-dom";
import { Grid, Card, CardContent, CardActionArea, Typography, Box } from "@mui/material";
import MovieIcon from "@mui/icons-material/Movie";
import TvIcon from "@mui/icons-material/Tv";
import BeachAccessIcon from "@mui/icons-material/BeachAccess";
import { useLanguage } from "../../context/LanguageContext";
import "./About.scss";

interface AboutPageProps {
  showUI: boolean;
}

const AboutPage: React.FC<AboutPageProps> = ({ showUI }) => {
  const { translate } = useLanguage();

  const hubCards = [
    {
      title: translate("about.moviesTitle"),
      description: translate("about.moviesDesc"),
      icon: <MovieIcon sx={{ fontSize: 40 }} />,
      path: "/about/movies",
      color: "#7be08b"
    },
    {
      title: translate("about.seriesTitle"),
      description: translate("about.seriesDesc"),
      icon: <TvIcon sx={{ fontSize: 40 }} />,
      path: "/about/series",
      color: "#3bc1b6"
    },
    {
      title: translate("about.vacationTitle"),
      description: translate("about.vacationDesc"),
      icon: <BeachAccessIcon sx={{ fontSize: 40 }} />,
      path: "/about/vacation",
      color: "#e09545"
    }
  ];

  const getHubColorClass = (index: number) => {
    switch (index) {
      case 0: return "color-movies";
      case 1: return "color-series";
      case 2: return "color-vacation";
      default: return "";
    }
  };

  return (
    <Box className={`about-container ui-fade ${showUI ? "visible" : ""}`}>
      <Box className="about-content">
        <Box className="about-header">
          <Typography variant="h2" component="h1" gutterBottom className="about-title">
            {translate("about.heading")}
          </Typography>
          <Typography variant="h6" color="text.secondary" className="about-subtitle">
            {translate("about.subtitle")}
          </Typography>
        </Box>

        <Grid container spacing={4}>
          {hubCards.map((card, index) => (
            <Grid item xs={12} sm={4} key={index}>
              <Card className="about-hub-card">
                <CardActionArea component={Link} to={card.path} className="about-hub-action">
                  <Box className={`about-hub-icon ${getHubColorClass(index)}`}>
                    {card.icon}
                  </Box>
                  <CardContent className="about-hub-content">
                    <Typography gutterBottom variant="h5" component="h2" className="about-hub-title">
                      {card.title}
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      {card.description}
                    </Typography>
                  </CardContent>
                </CardActionArea>
              </Card>
            </Grid>
          ))}
        </Grid>
      </Box>
    </Box>
  );
};

export default AboutPage;
